SELECT SUM(num) AS total_trades
FROM daily_market_data
WHERE stock_id = 1 AND date = '2023-05-01';

SELECT stock_id
FROM daily_market_data
WHERE date = '2023-05-01';

SELECT volume
FROM daily_market_data
WHERE stock_id = 0 AND date = '2023-05-01';

SELECT DISTINCT u.user_name
FROM access_logs a
INNER JOIN users u ON a.user_id = u.user_id;

SELECT stock_id
FROM daily_market_data
WHERE volume > 100000;

SELECT volume
FROM daily_market_data
WHERE stock_id = 0 AND date BETWEEN '2023-05-01' AND '2023-05-31';
